INSERT INTO `events` (`id`, `name`, `slug`, `image`, `desc`, `type`, `month`, `harga_contingent`, `harga_peserta`, `kotaOrKabupaten`, `lokasi`, `tgl_mulai_tanding`, `tgl_selesai_tanding`, `tgl_batas_pendaftaran`, `status`, `cp`, `juknis`, `total_hadiah`, `surat_rekom`, `created_at`, `updated_at`) VALUES
(5, 'KEJURCAB IX PAGAR NUSA SIDOARJO 2025', 'kejurcab-ix-pagar-nusa-sidoarjo-2025', 'event-images/kejurcab-ix-pagar-nusa-sidoarjo-20255-1756184575.jpg', '<div>&nbsp;Pencak silat merupakan seni beladiri tradisional yang memiliki berbagai ketentuan, keselarasan, keseimbangan, keserasian antara wirama, wirasa, dan wiraga. Juga menanamkan sikap berbudi pekerti yang luhur serta pengamalan falsafah Silat. Pagar Nusa ialah sebuah organisasi yang mempunyai tujuan untuk membentuk suatu wadah dibawah naungan Nahdlatul Ulama yang khusus mengembangkan seni bela diri pencak silat. Di sisi lain tumbuh berbagai perguruan pencak silat dengan segala keanekaragamannya berdasarkan segi agama, aqidah, kepercayaan dan jurus–jurus lainnya. Dalam organisasi ini diharuskan mengajarkan materi jurus baku dari PSNU Pagar Nusa sebagai bukti bahwa perguruan tradisional tersebut tergabung dalam PSNU Pagar Nusa.&nbsp;</div>', 'non-official', 'Oktober', 200000, NULL, 'SIDOARJO', 'Gedung Olahraga Sidoarjo', '2025-10-03', '2025-10-05', '2025-09-13', 2, '<div>&nbsp;<strong>BRI</strong> 166201010486502 / a.n. Tasya Shofwa Mahira <br><strong>CP</strong>&nbsp; 0877-0242-6911 /&nbsp; a.n. Mas Hoiri <br><strong>CP </strong>&nbsp;0897-6464-461 / a.n. Mas Feris&nbsp;</div>', 'https://drive.google.com/file/d/1WiOoyYIWzTzPZOq8-PfC-U2cXTZVmKEy/view?usp=sharing', 0, 'tidak wajib', '2025-08-26 05:02:55', '2025-08-26 08:33:01');
